def shortestSubarray(nums, k):
    n = len(nums)
    P = [0] * (n + 1)
    for i in range(n): P[i+1] = P[i] + nums[i]
    res = n + 1
    dq = collections.deque()
    for i, p in enumerate(P):
        while dq and p - P[dq[0]] >= k:
            res = min(res, i - dq.popleft())
        while dq and p <= P[dq[-1]]:
            dq.pop()
        dq.append(i)
    return res if res <= n else -1

